<template>
    <BaseModal
        name="release-kebab"
        :mobileMode="true"
        :closeOutside="true"
        :isLoading="data.loading"
    >
        <template v-slot:title>
            <div class="title">
                <div class="img" @click="gallery">
                    <Img v-if="data.item?.cover?.resized"
                        :preview="data.item?.cover?.resized"
                        :original="data.item?.cover?.original"
                        :alt="data.item?.title"
                        aspectRatio="1 / 1"
                    />
                </div>
                <span>{{ data.item?.title }}</span>
            </div>
        </template>
        <template v-slot:content>
            <ul class="kebab-list">
                <li class="clickable" @click="shareIt">
                    <Icon icon="share"/>
                    <span>{{ t('modals.release-kebab.share') }}</span>
                </li>
                <li class="clickable" @click="about">
                    <Icon icon="help"/>
                    <span>{{ t('modals.release-kebab.about') }}</span>
                </li>
                <li class="clickable" v-if="data.item?.id && releases.canEditOwnerSettings({ release: data.item })"
                    @click="setupReactions"
                >
                    <Icon icon="sticker"/>
                    <span>{{ t('modals.release-kebab.setup-reactions') }}</span>
                </li>
            </ul>
        </template>
    </BaseModal>
</template>

<script setup>
import { onMounted, reactive } from 'vue';
import { useI18n } from 'vue-i18n';

import Img from '🔗/components/ui/Img.vue';
import BaseModal from '🔗/components/modals/BaseModal.vue';
import stores from '@/stores';

import api from '🔗/api';
import { message } from '🔗/utils/utils';
import { RELEASE_REACTIONS } from '🔗/constants';

const { t } = useI18n();

const releases = api.releases();
// const messengers = stores.messengers();
const modals = stores.modals();
const share = stores.share();
const user = stores.user();

const data = reactive({
    loading: true
});


const shareIt = () => {
    close();

    share.release(data.item);
}

const about = () => {
    close();

    modals.open('release', { quietClose: true, data: {
        id: data.item.id,
        item: data.item
    } });
}

const setupReactions = () => {
    modals.open('options', {
        quietClose: true,
        data: {
            title: t('modals.release-kebab.setup-reactions'),
            options: RELEASE_REACTIONS.map(item => ({
                ...item,
                name: t(item.name)
            }))
        },
        callback: (code) => {
            if (!code) {
                return
            }

            close();

            modals.open('setup-reaction', {
                quietClose: true,
                data: {
                    code,
                    entityType: 'releases',
                    entityId: data.item.id
                }
            });
        }
    });
}

const gallery = () => {
    if (!data.item?.id || !data.item?.cover?.original) {
        return;
    }

    modals.open('gallery', {
        quietClose: true,
        data: { imgs: [{
            title: data.item.title,
            ...data.item?.cover
        }] } });
}

const close = () => {
    modals.close('release-kebab');
};


onMounted(async () => {
    const payload = modals.getData('release-kebab');

    if (!payload?.id) {
        close();
        return;
    }

    if (payload.item) {
        data.item = payload.item;
    } else {
        data.item = await releases.get(payload.id);
    }

    // Получаем артистов пользователя (если не получено ранее)
    await user.getArtists();

    data.loading = false;
});

</script>

<style lang="scss" scoped>
    .title {
        display: flex;
        width: 100%;
        align-items: center;
        gap: 24px;
        flex-direction: column;
        padding-top: 12px;

        .img {
            width: 74px;
            height: 74px;
            border-radius: 12px;
            @include animage-booble-shadow;

            img {
                width: 100%;
                height: 100%;
                border-radius: 12px;
            }
        }
    }

    ul.kebab-list {
        @include settings-list;
        margin-top: 24px;
    }
</style>
